class Solution {
public:
    string smallestNumber(string pattern) {
        string num = "";
        int i = 1;
        for (char c : pattern) {
            if (c == 'I') {
                num += to_string(i++);
            } else {
                num += to_string(9 - i + 1);
                i++;
            }
        }
        return num;
    }
};
